mapper.select:
SELECT emp_code, emp_name, dept_id, rank FROM emp
AND rank=#{rank}
AND dept_id=#{deptId}

SELECT fac_code, fac_name, fac_class_code, fac_status, not_start_date, not_end_date, fac_not_reason_code, emp_code, fac_not_code, FIND_EMP_NAME(emp_code) emp_name, get_mes_sub_code_name(fac_status) fac_status_name, get_mes_sub_code_name(fac_class_code) fac_class_name, get_mes_sub_code_name(fac_not_reason_code) fac_not_reason_name FROM ( SELECT f.fac_code, f.fac_name, f.fac_class_code, f.fac_status, n.fac_not_code, n.not_start_date, n.not_end_date, n.emp_code, n.fac_not_reason_code, ROW_NUMBER() OVER (PARTITION BY f.fac_code ORDER BY TO_NUMBER(substr(fac_not_code,7)) DESC) rn FROM fac f LEFT JOIN fac_not n ON f.fac_code = n.fac_code ) sub WHERE rn = 1
AND fac_status=#{facStatus}
AND fac_class_code=#{facClassCode}
ORDER BY TO_NUMBER(substr(fac_code,4)) DESC

